import type * as SarvamAI from "../index.js";
/**
 * Configuration parameters for Document Intelligence job. Specify the document language and desired output format.
 */
export interface DocDigitizationJobParameters {
    /** Primary language of the document in BCP-47 format. This helps optimize text extraction accuracy for the specified language. */
    language?: SarvamAI.DocDigitizationSupportedLanguage | undefined;
    /** Output format for the extracted content (delivered as a ZIP file). Use 'html' for structured HTML, 'md' for Markdown, or 'json' for structured JSON data. */
    output_format?: SarvamAI.DocDigitizationOutputFormat | undefined;
}
